font(.system(size: 22))                                .frame(width: 44, height: 44)                                .background(                                    Circle()                                        .fill(selectedIcon == icon ? Color.blue.opacity(0.2) : .clear)                                )                                .onTapGesture {                                    selectedIcon = icon                                }                        }                    }                    .padding(.vertical, 6)                }                Section("Цвет") {                    ScrollView(.horizontal, showsIndicators: false) {                        HStack(spacing: 12) {                            ForEach(availableColors, id: \.self) { hex in                                Circle()                                    .fill(Color(hex: hex) ?? .gray)                                    .frame(width: 32, height: 32)                                    .overlay(                                        Circle()                                            .stroke(Color.white, lineWidth: selectedColor == hex ? 3 : 0)                                    )                                    .onTapGesture {                                        selectedColor = hex                                    }                            }                        }                        .padding(.vertical, 8)                    }                }            }            .navigationTitle(category == nil ? "Новая категория" : "Изменить категорию")            .toolbar {                ToolbarItem(placement: .confirmationAction) {                    Button("Сохранить") {                        Task {                            let saved = try await save()                            onSave(saved)                            dismiss()                        }                    }                }                ToolbarItem(placement: .cancellationAction) {                    Button("Отмена") { dismiss() }                }            }        }    }    func save() async throws -> Category {        if let category {            // РЕДАКТИРОВАНИЕ            let dto = CategoryDto(                id: category.id,                name: name,                iconId: selectedIcon,                colorId: selectedColor,                type: selectedType            )            try await CategoryService.shared.update(id: category.id, dto: dto)            return dto.toModel()        } else {            // СОЗДАНИЕ            let dto = CreateCategoryDto(                name: name,                iconId: selectedIcon,                colorId: selectedColor,                type: selectedType            )            let created = try await CategoryService.shared.create(dto)            return created.toModel()        }    }}